### 4.8 定时器管理

**文件**：`task/timer.rs`

实现了 POSIX 间隔定时器（`setitimer`/`getitimer`）。

```rust
pub enum ITimerType {
    Real    = 0,  // SIGALRM
    Virtual = 1,  // SIGVTALRM
    Prof    = 2,  // SIGPROF
}

struct ITimer {
    interval_ns: usize,
    remained_ns: usize,
}

pub struct TimeManager {
    utime_ns: usize,
    stime_ns: usize,
    last_wall_ns: usize,
    state: TimerState,
    itimers: [ITimer; 3],
}

impl TimeManager {
    pub fn poll(&mut self, emitter: impl Fn(Signo)) {
        let now_ns = monotonic_time_nanos() as usize;
        let delta = now_ns - self.last_wall_ns;

        match self.state {
            TimerState::User => {
                self.utime_ns += delta;
                self.update_itimer(ITimerType::Virtual, delta, &emitter);
                self.update_itimer(ITimerType::Prof, delta, &emitter);
            }
            TimerState::Kernel => {
                self.stime_ns += delta;
                self.update_itimer(ITimerType::Prof, delta, &emitter);
            }
            TimerState::None => {}
        }
        self.update_itimer(ITimerType::Real, delta, &emitter);
        self.last_wall_ns = now_ns;
    }
}
