impl Pipe {
    pub fn new() -> (Pipe, Pipe) {
        let shared = Shared::new();
        shared.readers.store(1, Ordering::Release);
        shared.writers.store(1, Ordering::Release);

        let read_end = Pipe {
            read_side: true,
            shared: shared.clone(),
            non_blocking: AtomicBool::new(false),
            async_flag: AtomicBool::new(false),
        };
        let write_end = Pipe {
            read_side: false,
            shared,
            non_blocking: AtomicBool::new(false),
            async_flag: AtomicBool::new(false),
